var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하아...... 하아......","JPN":"はあ……はあ……","ENG":"*Huff, huff*","TWN":"哈啊……哈啊……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이, 이 정도로는 아직 멀었어요!","JPN":"こ、この程度は何でもありません！","ENG":"I-I'm not done yet!","TWN":"這、這種程度還差得遠呢！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"아직도 목이 뻣뻣하군요.","JPN":"まだ顔を上げる元気があるようですわね。","ENG":"You sure are stiff-necked.","TWN":"還真是倔強啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"고개를 조아리게 만들어 드리죠.","JPN":"ならば、地面だけしか見られないようにして差し上げましょう。","ENG":"Here, this will help you soften up.","TWN":"我會讓妳低下頭來的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"으윽......","JPN":"ううっ……","ENG":"Hngh...","TWN":"唔唔……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에, 에델?","JPN":"エ、エデル？","ENG":"E-Edel!","TWN":"艾、艾瑟兒？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"바보같이! 그런 걸 몸으로 막아내면 어떡해요!","JPN":"どういうつもりですか！　あんな攻撃を体で防ぐなんて！","ENG":"What were you thinking? You can't just jump in and block an attack with your body!","TWN":"笨蛋！怎麼能用身體去擋那種東西啊！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"말씀드렸잖아요...... 계승식 전까지는 저희가 꼭 지켜 드린다고......","JPN":"申し上げたはずです……継承式までは我々が必ずお守りしますと……","ENG":"Told you, Regina. We'd make sure nothing would happen to you until the succession ceremony's over...","TWN":"我不是說了嗎……繼承儀式結束之前，我們一定會保護您的……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"멍청한 소리 마! 두 번 다시 그랬다간 차기 학회장이고 뭐고 그만둘 거야! 알겠어?!","JPN":"馬鹿言わないで！　今度同じことをしたら、次期学会長になんかなりません！　わかりましたか！？","ENG":"Don't be stupid! You do that again, and I won't be the next President. Do you understand me?","TWN":"別說傻話了！妳要是再做這種事，我就不做什麼下任學會長了！知道了嗎？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"괜찮아요......","JPN":"大丈夫です……","ENG":"It's okay.","TWN":"不要緊……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"보셨다시피 전...... 쉽게 죽지 않거든요.","JPN":"ご覧の通り、我々は……簡単には死にませんから。","ENG":"As you saw, we don't die so easily.","TWN":"如您所見，我們……沒有那麼容易死掉。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"친우를 위해 몸을 던지다니, 그 희생정신에는 경의를 표해 드리죠.","JPN":"親友のために身を投げ打つとは、その自己犠牲の精神には敬意を示しましょう。","ENG":"You threw yourself to protect your comrade. I'd like to pay respect for that.","TWN":"竟然為了好朋友不顧自己的身體，我對這種犧牲精神表示尊敬。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 공과 사는 구분해야 하는 법, 이쯤에서 끝을 내도록 하겠습니다.","JPN":"ですが、公私は分けなければなりません。そろそろ終わりにしましょう。","ENG":"But this is something that needs to be done. I'll end you here.","TWN":"不過公私還是得分明，差不多該結束戰鬥了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......음?!","JPN":"……何です！？","ENG":"Hmm?","TWN":"……嗯？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>알비온 호, 좌현 피격! 기관실이 손상되었습니다!</color>","JPN":"<color=#ffd34c>アルビオン号、左舷被撃！　機関室が損傷しました！</color>","ENG":"<color=#ffd34c>Attack on portside! Damage in the engine room!</color>","TWN":"<color=#ffd34c>阿爾比恩號，左舷遭到襲擊！機艙受損！</color>"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};